    def _quantize_with_error_threshold(self, colors, method, kmeans, error_threshold):
        """
        Finds the smallest number of colors, up to ``colors``, for which the
        mean square error between this image and the quantized result is at
        or below ``error_threshold``, and returns the quantized core image.
        If no color count within the ``colors`` limit meets the threshold,
        ``colors`` colors are used.
        """

        from . import ImageChops, ImageStat

        reference = self if self.mode in ("RGB", "L") else self.convert("RGB")

        def mse(n):
            quantized = self._new(self.im.quantize(n, method, kmeans))
            comparison = quantized.convert(reference.mode)
            stat = ImageStat.Stat(ImageChops.difference(reference, comparison))
            return sum(stat.sum2) / sum(stat.count)

        lo, hi = 2, colors
        if mse(hi) > error_threshold:
            return self.im.quantize(hi, method, kmeans)

        while lo < hi:
            mid = (lo + hi) // 2
            if mse(mid) <= error_threshold:
                hi = mid
            else:
                lo = mid + 1

        return self.im.quantize(lo, method, kmeans)

